        // Inneren ein endlicher Wert; `_terrainMacroSurfaceY` trägt es.
        out.deltaZeroOutside = r._erosionDeltaAt(99999, 99999) === 0;
        out.deltaFiniteInside = Number.isFinite(r._erosionDeltaAt(0, 0));
