        out.structHasAerialOutput = !!(_structMat && _structMat.outputNode);
        // (3) der Builder ruft die EINE Quelle (Source-Probe: kein Parallel-Pfad).
        const _btSrc = r._buildToonNodeMaterial ? r._buildToonNodeMaterial.toString() : "";
