        check("Ring 6.4: Tempel hat ≥9 Parts (6 Pfeiler + Dach + Altar + Spitze)", ring64Results.templeHasParts);
        check("Ring 6.4: Wasserfall hat 3 Parts", ring64Results.waterfallHasParts);
